-- Add Management Style Diagnostic Test (MSDT) with 64 forced-choice items.
DO $$
DECLARE
  msdt_id UUID;
  new_question_id UUID;
  item JSONB;
BEGIN
  SELECT id INTO msdt_id
  FROM public.test_instruments
  WHERE name ILIKE '%MSDT%' OR name ILIKE '%Management Style Diagnostic%'
  LIMIT 1;

  IF msdt_id IS NULL THEN
    INSERT INTO public.test_instruments (
      name, name_en, description, category, scoring_method,
      target_audience, norm_reference, question_count, duration_minutes, is_active
    )
    VALUES (
      'MSDT',
      'Management Style Diagnostic Test',
      'Memetakan kecenderungan gaya manajemen melalui 64 pasangan pernyataan forced-choice.',
      'Behavioral',
      'msdt_style',
      'Supervisor, leader, manager, kandidat posisi struktural',
      'Management Style Diagnostic profile',
      64, 30, TRUE
    )
    RETURNING id INTO msdt_id;
  ELSE
    UPDATE public.test_instruments
    SET name = 'MSDT',
        name_en = 'Management Style Diagnostic Test',
        description = 'Memetakan kecenderungan gaya manajemen melalui 64 pasangan pernyataan forced-choice.',
        category = 'Behavioral',
        scoring_method = 'msdt_style',
        target_audience = 'Supervisor, leader, manager, kandidat posisi struktural',
        norm_reference = 'Management Style Diagnostic profile',
        question_count = 64,
        duration_minutes = 30,
        is_active = TRUE
    WHERE id = msdt_id;
  END IF;

  DELETE FROM public.test_question_options AS tqo
  USING public.test_questions AS tq
  WHERE tqo.question_id = tq.id
    AND tq.instrument_id = msdt_id;
  DELETE FROM public.test_questions WHERE instrument_id = msdt_id;

  FOR item IN
    SELECT jsonb_array_elements(($msdt$[{"n":1,"a":"Saya mengabaikan pelanggar-pelanggar peraturan bila saya merasa pasti bahwa tidak ada satu orangpun yang mengetahui tentang pelanggar-pelanggaran tersebut.","ac":"Laissez Faire","b":"Bila saya mengumumkan suatu keputusan yang kurang menyenangkan, saya akan menjelaskan kepada bawahan saya bahwa keputusan ini dibuat oleh Direktur.","bc":"Compromiser"},{"n":2,"a":"Bila ada seorang karyawan yang hasil kerjanya selalu tidak memuaskan saya, saya akan menunggu suatu kesempatan untuk memindahkannya dan bukan untuk memecatnya.","ac":"Human Relations","b":"Bila ada bawahan saya yang dikucilkan dari kelompok kerjanya, saya akan mencarikan cara-cara agar supaya orang lain dapat berteman dengannya.","bc":"Developer"},{"n":3,"a":"Bila Direktur memberikan perintah yang kurang menyenangkan, saya pikir adalah cukup bijaksana bila saya menyebutkan namanya dan bukan nama saya.","ac":"Compromiser","b":"Saya biasanya membuat keputusan-keputusan saya sendiri dan menyampaikannya kepada bawahan saya.","bc":"Autocratic"},{"n":4,"a":"Bila saya ditegur oleh atasan saya, saya akan memanggil semua bawahan saya dan mengatakan semua teguran tersebut kepada mereka.","ac":"Compromiser","b":"Saya selalu memberikan tugas-tugas yang sangat sulit kepada karyawan-karyawan yang paling berpengalaman.","bc":"Autocratic"},{"n":5,"a":"Saya selalu melakukan diskusi-diskusi untuk mencapai kata sepakat.","ac":"Democratic","b":"Saya selalu menganjurkan kepada bawahan saya untuk memberikan usul-usul, tetapi kadang-kadang juga saya langsung membuat suatu tindakan tertentu.","bc":"Executive"},{"n":6,"a":"Kadang-kadang saya berpikir bahwa perasaan-perasaan saya dan sikap-sikap saya adalah mementingkan tugas saya.","ac":"Autocratic","b":"Saya mengijinkan bawahan-bawahan saya untuk ikut serta di dalam pengambilan keputusan yang dibuat berdasarkan atas suara terbanyak.","bc":"Democratic"},{"n":7,"a":"Bila jumlah dan mutu hasil kerja bagian saya tidak memuaskan, saya menjelaskan kepada bawahan-bawahan saya bahwa Direktur merasa kecewa dan oleh karena itu mereka harus memperbaiki mutu kerja mereka itu.","ac":"Compromiser","b":"Saya membuat keputusan-keputusan sendiri dan kemudian saya mencoba untuk menjual keputusan-keputusan itu kepada bawahan saya.","bc":"Executive"},{"n":8,"a":"Bila saya mengumumkan suatu keputusan yang kurang menyenangkan, saya akan menjelaskan kepada bawahan saya bahwa keputusan ini dibuat oleh Direktur.","ac":"Compromiser","b":"Saya mengijinkan bawahan-bawahan saya untuk ikut serta di dalam pengambilan keputusan, tetapi sayapun menyediakan sesuatu keputusan terakhir.","bc":"Executive"},{"n":9,"a":"Saya akan memberikan tugas-tugas yang sulit kepada bawahan saya yang belum berpengalaman, tetapi bila mereka memperoleh kesukaran, saya akan mengambil alih tanggung jawab mereka.","ac":"Developer","b":"Saya selalu memberikan tugas-tugas yang sangat sulit kepada karyawan-karyawan yang paling berpengalaman.","bc":"Autocratic"},{"n":10,"a":"Saya merasa bahwa adalah penting agar bawahan-bawahan menyukai saya apabila saya bekerja keras untuk mereka.","ac":"Human Relations","b":"Saya membiarkan orang-orang lain menangani tugas-tugas mereka masing-masing, walaupun mereka membuat banyak kesalahan.","bc":"Laissez Faire"},{"n":11,"a":"Saya menunjukkan minat saya terhadap kehidupan pribadi bawahan-bawahan saya, sebab saya merasa bahwa sayapun mengerti mengapa mereka mengerjakan sesuatu hal sejauh mereka mengerjakan hal tersebut.","ac":"Human Relations","b":"Saya merasa bahwa adalah tidak terlalu perlu untuk bawahan-bawahan saya mengerti mengapa mereka mengerjakan sesuatu hal sejauh mereka mengerjakan hal tersebut.","bc":"Autocratic"},{"n":12,"a":"Saya percaya bahwa bawahan-bawahan yang disiplin tidak akan memperbaiki jumlah atau mutu kerja mereka di dalam jangka waktu yang panjang.","ac":"Laissez Faire","b":"Bila menghadapi masalah yang sulit, saya berusaha untuk mencapai pemecahan yang paling sedikit bisa diterima oleh sebagian besar orang-orang yang bersangkutan.","bc":"Compromiser"},{"n":13,"a":"Saya berpikir bahwa bila beberapa bawahan saya merasa tidak berbahagia, saya akan mencoba melakukan sesuatu mengenai hal tersebut.","ac":"Human Relations","b":"Saya mengurusi pekerjaan saya sendiri dan saya merasa bahwa pekerjaan saya itu bisa mencapai Dewan Direksi untuk mengembangkan ide-ide baru.","bc":"Executive"},{"n":14,"a":"Saya menyetujui kenaikan tunjangan-tunjangan untuk staf dan karyawan.","ac":"Human Relations","b":"Saya menunjukkan persetujuan untuk meningkatkan pengetahuan tentang pekerjaan dan perusahaan dari bawahan-bawahan saya, walaupun hal itu sebenarnya belum diperlukan untuk kedudukan mereka sekarang.","bc":"Developer"},{"n":15,"a":"Saya membiarkan orang-orang lain menangani tugas-tugas mereka masing-masing, walaupun mereka membuat banyak kesalahan.","ac":"Laissez Faire","b":"Saya membuat keputusan-keputusan sendiri, tetapi saya akan mempertimbangkan usul-usul yang masuk akal dari bawahan-bawahan saya untuk memperbaiki keputusan tersebut apabila saya bertanya kepada mereka.","bc":"Executive"},{"n":16,"a":"Bila ada bawahan saya yang dikucilkan dari kelompok kerjanya, saya akan mencarikan cara-cara agar supaya orang lain dapat berteman dengannya.","ac":"Developer","b":"Bila seorang karyawan tidak sanggup menyelesaikan tugasnya, saya akan membantu dia untuk menyelesaikan tugas tersebut.","bc":"Developer"},{"n":17,"a":"Saya percaya bahwa suatu penerapan disiplin adalah merupakan seperangkat contoh untuk karyawan-karyawan lainnya.","ac":"Bureaucratic","b":"Kadang-kadang saya berpikir bahwa perasaan-perasaan saya dan sikap-sikap saya adalah mementingkan tugas saya.","bc":"Autocratic"},{"n":18,"a":"Saya mencela pembicaraan-pembicaraan yang tidak perlu di antara bawahan-bawahan saya selama mereka bekerja.","ac":"Bureaucratic","b":"Saya menyetujui kenaikan tunjangan-tunjangan untuk staf dan karyawan.","bc":"Human Relations"},{"n":19,"a":"Saya selalu memperhatikan mengenai keterlambatan dan kemangkiran.","ac":"Bureaucratic","b":"Saya percaya bahwa Serikat-Serikat Buruh akan mencoba untuk meruntuhkan kewibawaan pimpinan perusahaan.","bc":"Bureaucratic"},{"n":20,"a":"Kadang-kadang saya menentang keluhan-keluhan Serikat Buruh sebagai sesuatu perkara yang prinsipil.","ac":"Bureaucratic","b":"Saya merasa bahwa keluhan-keluhan tidak dapat dicegah dan saya mencoba sebaik mungkin untuk dapat dilenyapkan.","bc":"Compromiser"},{"n":21,"a":"Adalah penting bagi saya untuk memperoleh nilai kredit bagi ide-ide saya yang baik.","ac":"Executive","b":"Saya menyuarakan pendapat-pendapat saya di muka umum hanya bila saya merasa bahwa orang lain akan setuju dengan saya.","bc":"Compromiser"},{"n":22,"a":"Saya percaya bahwa Serikat-Serikat Buruh akan mencoba untuk meruntuhkan kewibawaan pimpinan perusahaan.","ac":"Bureaucratic","b":"Saya percaya bahwa pertemuan-pertemuan yang sering dengan karyawan secara pribadi adalah membantu pengembangan diri mereka.","bc":"Developer"},{"n":23,"a":"Saya merasa bahwa adalah tidak terlalu perlu untuk bawahan-bawahan saya mengerti mengapa mereka mengerjakan sesuatu hal sejauh mereka mengerjakan hal tersebut.","ac":"Autocratic","b":"Saya merasa bahwa jam pencatat waktu datang dan pulangnya para pegawai, mengurangi keterlambatan.","bc":"Bureaucratic"},{"n":24,"a":"Saya biasanya membuat keputusan-keputusan saya sendiri dan menyampaikannya kepada bawahan saya.","ac":"Autocratic","b":"Saya percaya bahwa Serikat-Serikat Buruh dan pimpinan perusahaan adalah bekerja untuk mencapai tujuan-tujuan yang sama.","bc":"Democratic"},{"n":25,"a":"Saya menyukai penggunaan dari skala penggajian karyawan.","ac":"Bureaucratic","b":"Saya selalu melakukan diskusi-diskusi untuk mencapai kata sepakat.","bc":"Democratic"},{"n":26,"a":"Saya merasa bangga di dalam kenyataannya bahwa saya biasanya tidak akan menanyakan kepada seseorang untuk mengerjakan suatu tugas yang kalau untuk saya sendiri, tidak akan saya kerjakan.","ac":"Executive","b":"Saya berpikir bahwa bila beberapa bawahan saya merasa tidak berbahagia, saya akan mencoba melakukan sesuatu mengenai hal tersebut.","bc":"Human Relations"},{"n":27,"a":"Bila ada suatu tugas yang mendesak, walaupun semua peralatannya sudah disediakan, saya akan membiarkannya saja dan mengatakan kepada salah seorang bawahan saya untuk mengerjakan tugas tersebut.","ac":"Laissez Faire","b":"Adalah penting bagi saya untuk memperoleh nilai kredit bagi ide-ide saya yang baik.","bc":"Executive"},{"n":28,"a":"Tujuan saya adalah mencapai bagaimana tugas-tugas dapat dikerjakan, tanpa saya merasa lebih benci daripada siapapun yang mengerjakannya.","ac":"Compromiser","b":"Saya mungkin menentukan tugas-tugas tanpa banyak mempertimbangkan pengalaman atau kemampuan, tetapi saya lebih menuntut pada pencapaian hasil-hasilnya saja.","bc":"Autocratic"},{"n":29,"a":"Saya mungkin menentukan tugas-tugas tanpa banyak mempertimbangkan pengalaman atau kemampuan, tetapi saya lebih menuntut pada pencapaian hasil-hasilnya saja.","ac":"Autocratic","b":"Saya dengan sabar mendengarkan keluhan-keluhan dan ketidakpuasan-ketidakpuasan dari bawahan saya, tetapi seringkali saya meralat apa yang mereka katakan.","bc":"Compromiser"},{"n":30,"a":"Saya merasa bahwa keluhan-keluhan tidak dapat dicegah dan saya mencoba sebaik mungkin untuk dapat dilenyapkan.","ac":"Compromiser","b":"Saya percaya bahwa bawahan-bawahan saya akan merasakan kepuasan kerja mereka tanpa merasakan tekanan apa pun dari saya.","bc":"Human Relations"},{"n":31,"a":"Bila menghadapi masalah yang sulit, saya berusaha untuk mencapai pemecahan yang paling sedikit bisa diterima oleh sebagian besar orang-orang yang bersangkutan.","ac":"Compromiser","b":"Saya percaya bahwa latihan melalui pengalaman bekerja, adalah lebih bermanfaat daripada pendidikan teoritis.","bc":"Developer"},{"n":32,"a":"Saya selalu memberikan tugas-tugas yang sangat sulit kepada karyawan-karyawan yang paling berpengalaman.","ac":"Autocratic","b":"Saya percaya bahwa kenaikan jabatan adalah semata-mata berdasarkan kemampuan yang ada.","bc":"Bureaucratic"},{"n":33,"a":"Saya merasa bahwa masalah-masalah yang timbul di antara para karyawan biasanya akan dapat diselesaikan di antara mereka sendiri, tanpa campur tangan dari saya.","ac":"Laissez Faire","b":"Bila saya ditegur oleh atasan saya, saya akan memanggil semua bawahan saya dan mengatakan semua teguran tersebut kepada mereka.","bc":"Compromiser"},{"n":34,"a":"Saya tidak peduli dengan apa yang dikerjakan oleh para pegawai saya di luar jam kerja kantornya.","ac":"Laissez Faire","b":"Saya percaya bahwa bawahan-bawahan yang disiplin tidak akan memperbaiki jumlah atau mutu kerja mereka di dalam jangka waktu yang panjang.","bc":"Laissez Faire"},{"n":35,"a":"Saya memberikan informasi kepada Dewan Direksi tidak lebih daripada apa yang mereka tanyakan.","ac":"Bureaucratic","b":"Kadang-kadang saya menentang keluhan-keluhan Serikat Buruh sebagai sesuatu perkara yang prinsipil.","bc":"Bureaucratic"},{"n":36,"a":"Saya kadang-kadang merasa ragu-ragu untuk membuat suatu keputusan yang akan tidak disukai oleh bawahan-bawahan saya.","ac":"Compromiser","b":"Tujuan saya adalah mencapai bagaimana tugas-tugas dapat dikerjakan, tanpa saya merasa lebih benci daripada siapapun yang mengerjakannya.","bc":"Compromiser"},{"n":37,"a":"Saya dengan sabar mendengarkan keluhan-keluhan dan ketidakpuasan-ketidakpuasan dari bawahan saya, tetapi seringkali saya meralat apa yang mereka katakan.","ac":"Compromiser","b":"Saya kadang-kadang merasa ragu-ragu untuk membuat suatu keputusan yang akan tidak disukai oleh bawahan-bawahan saya.","bc":"Compromiser"},{"n":38,"a":"Saya menyuarakan pendapat-pendapat saya di muka umum hanya bila saya merasa bahwa orang lain akan setuju dengan saya.","ac":"Compromiser","b":"Sebagian besar dari bawahan-bawahan saya dapat menyelesaikan tugas-tugas mereka, bila perlu, tanpa kehadiran saya.","bc":"Laissez Faire"},{"n":39,"a":"Saya mengurusi pekerjaan saya sendiri dan saya merasa bahwa pekerjaan saya itu bisa mencapai Dewan Direksi untuk mengembangkan ide-ide baru.","ac":"Executive","b":"Bila saya memberikan perintah kepada bawahan-bawahan saya, saya menentukan batas waktu untuk mereka menyelesaikannya.","bc":"Autocratic"},{"n":40,"a":"Saya selalu menganjurkan kepada bawahan saya untuk memberikan usul-usul, tetapi kadang-kadang juga saya langsung membuat suatu tindakan tertentu.","ac":"Executive","b":"Saya mencoba untuk membuat bawahan-bawahan saya merasa senang hatinya apabila mereka berbicara dengan saya.","bc":"Human Relations"},{"n":41,"a":"Di dalam diskusi, saya memberikan fakta-fakta seperti apa yang mereka pahami, dan membiarkan mereka melukiskan kesimpulan-kesimpulan mereka sendiri.","ac":"Democratic","b":"Bila Direktur memberikan perintah yang kurang menyenangkan, saya pikir adalah cukup bijaksana bila saya menyebutkan namanya dan bukan nama saya.","bc":"Compromiser"},{"n":42,"a":"Bila ada tugas-tugas yang tidak dikehendaki yang harus dikerjakan, sebelumnya saya akan menanyakan kepada beberapa sukarelawan yang mau mengerjakan tugas tersebut.","ac":"Democratic","b":"Saya menunjukkan minat saya terhadap kehidupan pribadi bawahan-bawahan saya, sebab saya merasa bahwa sayapun mengharapkan mereka berbuat seperti itu kepada saya.","bc":"Human Relations"},{"n":43,"a":"Saya adalah seorang yang sangat memperhatikan kebahagiaan karyawan-karyawan saya di dalam mereka mengerjakan tugas-tugas mereka.","ac":"Human Relations","b":"Saya selalu memperhatikan mengenai keterlambatan dan kemangkiran.","bc":"Bureaucratic"},{"n":44,"a":"Sebagian besar dari bawahan-bawahan saya dapat menyelesaikan tugas-tugas mereka, bila perlu, tanpa kehadiran saya.","ac":"Laissez Faire","b":"Bila ada suatu tugas yang mendesak, walaupun semua peralatannya sudah disediakan, saya akan membiarkannya saja dan mengatakan kepada salah seorang bawahan saya untuk mengerjakan tugas tersebut.","bc":"Laissez Faire"},{"n":45,"a":"Saya percaya bahwa bawahan-bawahan saya akan merasakan kepuasan kerja mereka tanpa merasakan tekanan apa pun dari saya.","ac":"Human Relations","b":"Saya memberikan informasi kepada Dewan Direksi tidak lebih daripada apa yang mereka tanyakan.","bc":"Bureaucratic"},{"n":46,"a":"Saya percaya bahwa pertemuan-pertemuan yang sering dengan karyawan secara pribadi adalah membantu pengembangan diri mereka.","ac":"Developer","b":"Saya adalah seorang yang sangat memperhatikan kebahagiaan karyawan-karyawan saya di dalam mereka mengerjakan tugas-tugas mereka.","bc":"Human Relations"},{"n":47,"a":"Saya menunjukkan persetujuan untuk meningkatkan pengetahuan tentang pekerjaan dan perusahaan dari bawahan-bawahan saya, walaupun hal itu sebenarnya belum diperlukan untuk kedudukan mereka sekarang.","ac":"Developer","b":"Saya mengawasi benar bawahan-bawahan saya yang kurang mahir di dalam bekerjanya atau bawahan-bawahan saya yang hasil kerjanya kurang memuaskan.","bc":"Autocratic"},{"n":48,"a":"Saya mengijinkan bawahan-bawahan saya untuk ikut serta di dalam pengambilan keputusan yang dibuat berdasarkan atas suara terbanyak.","ac":"Democratic","b":"Saya membuat bawahan-bawahan saya bekerja keras, dan saya berusaha menyakinkan mereka bahwa biasanya mereka mendapat perlakuan yang adil dari Dewan Direksi.","bc":"Autocratic"},{"n":49,"a":"Saya merasa bahwa semua karyawan pada jabatan yang sama seharusnya memperoleh gaji yang sama.","ac":"Bureaucratic","b":"Bila ada seorang karyawan yang hasil kerjanya selalu tidak memuaskan saya, saya akan menunggu suatu kesempatan untuk memindahkannya dan bukan untuk memecatnya.","bc":"Human Relations"},{"n":50,"a":"Saya merasa bahwa tujuan-tujuan Serikat Buruh dan tujuan-tujuan perusahaan adalah saling berbeda, dan saya mencoba untuk tidak membuat pandangan saya secara jelas.","ac":"Compromiser","b":"Saya merasa bahwa adalah penting agar bawahan-bawahan menyukai saya apabila saya bekerja keras untuk mereka.","bc":"Human Relations"},{"n":51,"a":"Saya mengawasi benar bawahan-bawahan saya yang kurang mahir di dalam bekerjanya atau bawahan-bawahan saya yang hasil kerjanya kurang memuaskan.","ac":"Autocratic","b":"Saya mencela pembicaraan-pembicaraan yang tidak perlu di antara bawahan-bawahan saya selama mereka bekerja.","bc":"Bureaucratic"},{"n":52,"a":"Bila saya memberikan perintah kepada bawahan-bawahan saya, saya menentukan batas waktu untuk mereka menyelesaikannya.","ac":"Autocratic","b":"Saya merasa bangga di dalam kenyataannya bahwa saya biasanya tidak akan menanyakan kepada seseorang untuk mengerjakan suatu tugas yang kalau untuk saya sendiri, tidak akan saya kerjakan.","bc":"Executive"},{"n":53,"a":"Saya percaya bahwa latihan melalui pengalaman bekerja, adalah lebih bermanfaat daripada pendidikan teoritis.","ac":"Developer","b":"Saya tidak peduli dengan apa yang dikerjakan oleh para pegawai saya di luar jam kerja kantornya.","bc":"Laissez Faire"},{"n":54,"a":"Saya merasa bahwa jam pencatat waktu datang dan pulangnya para pegawai, mengurangi keterlambatan.","ac":"Bureaucratic","b":"Saya mengijinkan bawahan-bawahan saya untuk ikut serta di dalam pengambilan keputusan yang dibuat berdasarkan atas suara terbanyak.","bc":"Democratic"},{"n":55,"a":"Saya membuat keputusan-keputusan sendiri, tetapi saya akan mempertimbangkan usul-usul yang masuk akal dari bawahan-bawahan saya untuk memperbaiki keputusan tersebut apabila saya bertanya kepada mereka.","ac":"Executive","b":"Saya merasa bahwa tujuan-tujuan Serikat Buruh dan tujuan-tujuan perusahaan adalah saling berbeda, dan saya mencoba untuk tidak membuat pandangan saya secara jelas.","bc":"Compromiser"},{"n":56,"a":"Saya membuat keputusan-keputusan sendiri dan kemudian saya mencoba untuk menjual keputusan-keputusan itu kepada bawahan saya.","ac":"Executive","b":"Saya membentuk kelompok-kelompok kerja yang terdiri dari orang-orang yang sudah menjadi teman-teman baik saya.","bc":"Human Relations"},{"n":57,"a":"Saya tidak akan ragu-ragu untuk mempekerjakan pegawai-pegawai yang cacat jasmaninya, bilamana saya merasa pasti bahwa dia dapat mempelajari pekerjaannya.","ac":"Developer","b":"Saya mengabaikan pelanggar-pelanggar peraturan bila saya merasa pasti bahwa tidak ada satu orangpun yang mengetahui tentang pelanggar-pelanggaran tersebut.","bc":"Laissez Faire"},{"n":58,"a":"Saya membentuk kelompok-kelompok kerja yang terdiri dari orang-orang yang sudah menjadi teman-teman baik saya.","ac":"Human Relations","b":"Saya akan memberikan tugas-tugas yang sulit kepada bawahan saya yang belum berpengalaman, tetapi bila mereka memperoleh kesukaran, saya akan mengambil alih tanggung jawab mereka.","bc":"Developer"},{"n":59,"a":"Saya membuat bawahan-bawahan saya bekerja keras, dan saya berusaha menyakinkan mereka bahwa biasanya mereka mendapat perlakuan yang adil dari Dewan Direksi.","ac":"Autocratic","b":"Saya percaya bahwa suatu penerapan disiplin adalah merupakan seperangkat contoh untuk karyawan-karyawan lainnya.","bc":"Bureaucratic"},{"n":60,"a":"Saya mencoba untuk membuat bawahan-bawahan saya merasa senang hatinya apabila mereka berbicara dengan saya.","ac":"Human Relations","b":"Saya menyukai penggunaan dari skala penggajian karyawan.","bc":"Bureaucratic"},{"n":61,"a":"Saya percaya bahwa kenaikan jabatan adalah semata-mata berdasarkan kemampuan yang ada.","ac":"Bureaucratic","b":"Saya merasa bahwa masalah-masalah yang timbul di antara para karyawan biasanya akan dapat diselesaikan di antara mereka sendiri, tanpa campur tangan dari saya.","bc":"Laissez Faire"},{"n":62,"a":"Saya percaya bahwa Serikat-Serikat Buruh dan pimpinan perusahaan adalah bekerja untuk mencapai tujuan-tujuan yang sama.","ac":"Democratic","b":"Di dalam diskusi, saya memberikan fakta-fakta seperti apa yang mereka pahami, dan membiarkan mereka melukiskan kesimpulan-kesimpulan mereka sendiri.","bc":"Democratic"},{"n":63,"a":"Bila seorang karyawan tidak sanggup menyelesaikan tugasnya, saya akan membantu dia untuk menyelesaikan tugas tersebut.","ac":"Developer","b":"Saya merasa bahwa semua karyawan pada jabatan yang sama seharusnya memperoleh gaji yang sama.","bc":"Bureaucratic"},{"n":64,"a":"Saya mengijinkan bawahan-bawahan saya untuk ikut serta di dalam pengambilan keputusan, tetapi sayapun menyediakan sesuatu keputusan terakhir.","ac":"Executive","b":"Saya tidak akan ragu-ragu untuk mempekerjakan pegawai-pegawai yang cacat jasmaninya, bilamana saya merasa pasti bahwa dia dapat mempelajari pekerjaannya.","bc":"Developer"}]$msdt$)::jsonb)
